sql:
SELECT DISTINCT file_language
FROM files
WHERE loc > 10000 AND authors > 10;

SELECT DISTINCT u.user_id, u.user_name, u.email, u.role, u.status
FROM users u
JOIN access_logs a ON u.user_id = a.user_id;

SELECT project_name, julianday(end_date) - julianday(start_date) AS project_duration
FROM projects
WHERE julianday(end_date) - julianday(start_date) = (
    SELECT MAX(julianday(end_date) - julianday(start_date))
    FROM projects
);

SELECT user_id, user_name
FROM users
WHERE user_id > (SELECT AVG(user_id) FROM users);

SELECT DISTINCT file_type
FROM files
WHERE actual = 1 AND file_type <> 'source code';

